import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int value;
        Node next, prev;
        Node(int v) { value = v; }
    }
    static Node deleteNode(Node head, int value) {
        Node target = head;
        while (target != null && target.value != value) target = target.next;
        if (target == null) return head; // value not found, shouldn't happen per constraints
        Node A = target.prev;
        Node B = target.next;
        if (A != null) A.next = B;
        if (B != null) B.prev = A;
        if (target == head) head = B;
        return head;
    }
    public static void main(String[] args) throws Exception {
        // Read entire input as a single string to handle escaped "\\n" sequences in test data
        String data = new String(System.in.readAllBytes());
        // Replace literal "\\n" with a space (or actual newline) to act as delimiter
        data = data.replace("\\n", " ");
        // Use a Scanner with whitespace delimiter
        Scanner sc = new Scanner(data);
        StringBuilder out = new StringBuilder();
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int x = sc.nextInt();
            Node head = null, cur = null;
            for (int i = 0; i < n; ++i) {
                int v = sc.nextInt();
                Node nd = new Node(v);
                if (head == null) { head = nd; cur = nd; }
                else { cur.next = nd; nd.prev = cur; cur = nd; }
            }
            head = deleteNode(head, x);
            Node p = head;
            while (p != null) {
                out.append(p.value);
                if (p.next != null) out.append(' ');
                p = p.next;
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

